mapper.sql:
where


        idx.type in

            #{type}



        idx.type = 2



    and idx.nsfw = 0


    and idx.year >= #{minYear}


    and idx.year <= #{maxYear}


    and idx.score >= #{minRating}


    and idx.score <= #{maxRating}


    and idx.subject_rank >= #{minRank}


    and idx.subject_rank > 0
    and idx.subject_rank <= #{maxRank}



        and idx.tags_text like concat('%', #{tag}, '%')




        and idx.meta_tags_text like concat('%', #{metaTag}, '%')


and (

        idx.subject_id = #{exactSubjectId}
        or

    idx.name like concat('%', #{keyword}, '%')
    or idx.name_cn like concat('%', #{keyword}, '%')
    or idx.aliases like concat('%', #{keyword}, '%')
    or  like concat('%', #{compactKeyword}, '%')
    or  like concat('%', #{compactKeyword}, '%')
    or  like concat('%', #{compactKeyword}, '%')

        or  like concat('%', #{anchorKeyword}, '%')
        or  like concat('%', #{anchorKeyword}, '%')
        or  like concat('%', #{anchorKeyword}, '%')


        or match(idx.name, idx.name_cn, idx.aliases, idx.tags_text, idx.meta_tags_text, idx.search_text)
           against(#{keyword} in natural language mode)

)

mapper.select:
select candidate.id, candidate.type, candidate.name, candidate.name_cn, candidate.infobox, candidate.nsfw, candidate.score, candidate.score_details, candidate.`rank`, candidate.images from ( select s.id, s.type, s.name, s.name_cn, s.infobox, s.nsfw, s.score, s.score_details, s.`rank`, s.`date`, s.images,
( select count(distinct subject_tag.name) from json_table(coalesce(s.tags, cast('[]' as json)), '$[*]' columns (name varchar(128) path '$.name')) subject_tag where subject_tag.name in
#{tagName}
)
0 as tag_matches,
( select count(distinct subject_meta.name) from json_table(coalesce(s.meta_tags, cast('[]' as json)), '$[*]' columns (name varchar(128) path '$')) subject_meta where subject_meta.name in
#{metaTagName}
)
0 as meta_matches from bangumi_subject s where s.id != #{subjectId} and s.type = #{type} and s.nsfw = #{nsfw} ) candidate where candidate.tag_matches > 0 or candidate.meta_matches > 0 or (candidate.`rank` is not null and candidate.`rank` > 0) order by ( candidate.tag_matches * 10 + candidate.meta_matches * 6 + case when #{releaseYear} is not null and candidate.`date` regexp '^[0-9]{4}' then greatest(0, 4 - least(4, abs(cast(substring(candidate.`date`, 1, 4) as signed) - #{releaseYear}))) else 0 end + coalesce(candidate.score, 0) + case when candidate.`rank` is not null and candidate.`rank` > 0 then greatest(0, 5 - least(candidate.`rank`, 5000) / 1000) else 0 end ) desc, candidate.`rank` is null, candidate.`rank` = 0, candidate.`rank`, candidate.score desc, candidate.id limit #{limit} offset #{offset}
